/**
 * Templates used to render CTB-generated rename migrations.
 *
 * These are kept as plain string templates (with `{{token}}` placeholders) in a
 * dedicated module rather than inline in the builder logic so they read like the
 * generated file and can evolve independently. We intentionally avoid pulling in
 * a templating engine (e.g. Handlebars) for such a small surface — see
 * CTB_RENAME_QUESTIONS.md #4.
 *
 * We always emit CommonJS `.js` migrations — never `.ts` — even in TypeScript
 * projects. The migration runner only globs `*.{js,sql}` (see
 * packages/core/database/src/migrations/users.ts), and when
 * `useTypescriptMigrations` is enabled the migrations dir resolves to the
 * compiled output dir, so a `.ts` file written at runtime would silently never
 * run and data would be lost. A plain `.js` migration runs in both cases.
 *
 * Every operation is guarded (existence checks) so the whole migration is a safe
 * no-op on a fresh database, where the tables/columns do not exist yet.
 */

const JS_TEMPLATE = `'use strict';

/**
 * Auto-generated by the Strapi Content-Type Builder on {{timestamp}}.
 *
 * Preserves data when fields are renamed in the Content-Type Builder by renaming
 * the underlying database artifacts (columns, relation join tables/columns, and
 * component link references) before schema-sync runs. Guarded so it is a safe
 * no-op on a fresh database.
 */
module.exports = {
  async up(knex) {
{{body}}
  },
  async down(knex) {
    // Down migrations are not generated for CTB rename migrations.
  },
};
`;

// Scalar columns and relation join columns (e.g. `field_id`) live on a model's
// own table — a guarded `renameColumn`.
const RENAME_COLUMN_SNIPPET = `    // {{comment}}
    if (await knex.schema.hasColumn('{{table}}', '{{from}}')) {
      await knex.schema.alterTable('{{table}}', (table) => {
        table.renameColumn('{{from}}', '{{to}}');
      });
    }`;

// Relations backed by a join/link table encode the attribute name in the table
// name — a guarded `renameTable`. The guard also checks the destination does not
// already exist so re-runs / fresh DBs are safe.
const RENAME_TABLE_SNIPPET = `    // {{comment}}
    if (
      (await knex.schema.hasTable('{{from}}')) &&
      !(await knex.schema.hasTable('{{to}}'))
    ) {
      await knex.schema.renameTable('{{from}}', '{{to}}');
    }`;

// Components, dynamic zones and media store the attribute name as a *value* in
// the `field` column of a link table — a guarded data `UPDATE`, not DDL. Media
// uses the shared `files_related_morphs` table, so the update must also be
// scoped by the owning type (`related_type`); components/DZ use a per-type link
// table and need no such filter.
const UPDATE_COMPONENT_FIELD_SNIPPET = `    // {{comment}}
    if (await knex.schema.hasColumn('{{table}}', '{{fieldColumn}}')) {
      await knex('{{table}}').where('{{fieldColumn}}', '{{from}}'){{typeFilter}}.update('{{fieldColumn}}', '{{to}}');
    }`;

const interpolate = (template: string, values: Record<string, string>): string => {
  return template.replace(/\{\{\s*(\w+)\s*\}\}/g, (_match, key: string) => {
    return key in values ? values[key] : `{{${key}}}`;
  });
};

/**
 * A single physical operation, emitted in the exact order the user performed the
 * renames in the Content-Type Builder. That order is inherently collision-free
 * (the CTB forbids duplicate field names), so the operations replay verbatim and
 * never need a synthetic temporary artifact.
 *
 * - `renameColumn`: scalar attributes and relation join columns (`<field>_id`).
 * - `renameTable`: relations backed by a join/link table.
 * - `updateComponentField`: components, dynamic zones & media (link-table `field`
 *   value). Media additionally scopes the update by `related_type` since it uses
 *   the shared `files_related_morphs` table.
 */
export type PhysicalOp =
  | { kind: 'renameColumn'; table: string; from: string; to: string; comment: string }
  | { kind: 'renameTable'; from: string; to: string; comment: string }
  | {
      kind: 'updateComponentField';
      table: string;
      fieldColumn: string;
      from: string;
      to: string;
      comment: string;
      // Optional extra equality filter (used by media on the shared morph table).
      typeColumn?: string;
      typeValue?: string;
    };

export const renderOperation = (op: PhysicalOp): string => {
  switch (op.kind) {
    case 'renameTable':
      return interpolate(RENAME_TABLE_SNIPPET, {
        comment: op.comment,
        from: op.from,
        to: op.to,
      });
    case 'updateComponentField': {
      const typeFilter =
        op.typeColumn && op.typeValue !== undefined
          ? `.where('${op.typeColumn}', '${op.typeValue}')`
          : '';
      return interpolate(UPDATE_COMPONENT_FIELD_SNIPPET, {
        comment: op.comment,
        table: op.table,
        fieldColumn: op.fieldColumn,
        from: op.from,
        to: op.to,
        typeFilter,
      });
    }
    case 'renameColumn':
    default:
      return interpolate(RENAME_COLUMN_SNIPPET, {
        comment: op.comment,
        table: op.table,
        from: op.from,
        to: op.to,
      });
  }
};

export const renderMigration = ({
  timestamp,
  operations,
}: {
  timestamp: string;
  operations: PhysicalOp[];
}): string => {
  const body = operations.map(renderOperation).join('\n\n');
  return interpolate(JS_TEMPLATE, { timestamp, body });
};
